              <i className="fas fa-exclamation-circle mr-2"></i>
              {state.error}
            </div>
          )}
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <nav className="flex items-center justify-between px-6 pt-6 border-b border-gray-200 bg-white">
          <div className="flex items-center">
            <button
              onClick={() => setActiveTab(TabType.SUMMARY)}
              className={`px-6 py-3 text-sm font-semibold transition-all border-b-2 ${
                activeTab === TabType.SUMMARY 
                  ? 'border-indigo-600 text-indigo-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Summary
            </button>
            <button
              onClick={() => setActiveTab(TabType.CHAT)}
              className={`px-6 py-3 text-sm font-semibold transition-all border-b-2 ${
                activeTab === TabType.CHAT 
                  ? 'border-indigo-600 text-indigo-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Ask Questions
            </button>
          </div>

          {activeTab === TabType.CHAT && messages.length > 0 && (
            <button
              onClick={handleClearHistory}
              className="text-xs text-red-500 hover:text-red-700 font-medium px-4 py-2 rounded-lg hover:bg-red-50 transition-all flex items-center gap-1"
            >
              <i className="fas fa-trash-alt"></i>
              Clear Chat
            </button>
          )}
        </nav>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar">
          {activeTab === TabType.SUMMARY ? (
            <div className="max-w-4xl mx-auto space-y-6">
              {!state.summary && !state.isProcessing ? (
                <div className="flex flex-col items-center justify-center py-20 text-gray-400">
                  <i className="fas fa-file-alt text-6xl mb-4 opacity-20"></i>
                  <p className="text-lg">Paste content or upload a file to start.</p>
                </div>
              ) : state.isProcessing ? (
                <div className="space-y-4 animate-pulse">
                  <div className="h-8 bg-gray-200 rounded w-1/4"></div>
                  <div className="h-4 bg-gray-200 rounded w-full"></div>
                  <div className="h-4 bg-gray-200 rounded w-full"></div>
                  <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                </div>
              ) : (
                <article className="prose prose-indigo max-w-none bg-white p-8 rounded-2xl shadow-sm border border-gray-100 relative">
                  <div className="flex justify-between items-start mb-6">
                    <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                      <i className="fas fa-clipboard-list text-indigo-600"></i>
                      Context Summary
                    </h2>
                    <button
                      onClick={handleExport}
                      className="flex items-center gap-2 px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 text-sm font-semibold rounded-lg transition-colors"
                      title="Export to Text File"
                    >
                      <i className="fas fa-file-export"></i>
                      Export .txt
                    </button>
                  </div>
                  <div className="text-gray-700 leading-relaxed whitespace-pre-wrap">
                    {state.summary}
                  </div>
                </article>
              )}
            </div>
          ) : (
            <div className="max-w-4xl mx-auto h-full flex flex-col">
              <div className="flex-1 overflow-y-auto space-y-4 pb-4 custom-scrollbar">
                {messages.length === 0 && (
                  <div className="flex flex-col items-center justify-center py-20 text-gray-400">
                    <i className="fas fa-comments text-6xl mb-4 opacity-20"></i>
                    <p className="text-center">Ask anything about the context provided.<br/>The model will remember the conversation.</p>
                  </div>
                )}
                {messages.map((msg, idx) => (
                  <div
                    key={idx}
                    className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
                  >
                    <div className="mb-1 px-2 flex items-center gap-2">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                        {msg.role === 'user' ? 'You' : 'Assistant'}
                      </span>
                    </div>
                    <div
                      className={`max-w-[85%] p-4 rounded-2xl shadow-sm relative group ${
                        msg.role === 'user'
                          ? 'bg-indigo-600 text-white rounded-tr-none'
                          : msg.isError 
                            ? 'bg-red-50 text-red-800 border border-red-200 rounded-tl-none'
                            : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
                      }`}
                    >
                      <div className="flex items-start gap-2">
                        {msg.isError && <i className="fas fa-exclamation-triangle mt-1"></i>}
                        <div className="text-sm whitespace-pre-wrap">{msg.content}</div>
                      </div>

                      <div className="flex items-center justify-between mt-2 pt-2 border-t border-black/5">
                        <span className={`text-[10px] block opacity-50`}>
                          {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                        {msg.isError && (
                          <button 
                            onClick={handleRetry}
                            className="text-[10px] font-bold underline hover:no-underline transition-all flex items-center gap-1"
                          >
                            <i className="fas fa-redo text-[8px]"></i>
                            Retry
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
                {isChatting && (
                  <div className="flex flex-col items-start">
                    <div className="mb-1 px-2">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Assistant</span>
                    </div>
                    <div className="bg-white text-gray-400 border border-gray-100 rounded-2xl rounded-tl-none p-4 shadow-sm flex items-center gap-3">
                      <div className="flex gap-1">
                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                        <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></span>
                      </div>
                      <span className="text-sm">Analyzing context...</span>
                    </div>
                  </div>
                )}
                <div ref={chatEndRef} />
              </div>

              <div className="pt-4 mt-auto border-t border-gray-100">
                <form onSubmit={handleSendMessage} className="flex gap-2 relative">
                  <input
                    type="text"
                    placeholder={!state.summary ? "Analyze context first to chat..." : isChatting ? "Thinking..." : "Type your message..."}
                    className="flex-1 p-4 pr-16 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none text-sm bg-white shadow-sm disabled:bg-gray-50 transition-all"
                    value={inputMessage}
                    onChange={(e) => setInputMessage(e.target.value)}
                    disabled={!state.summary || isChatting}
                  />
                  <button
                    type="submit"
                    disabled={!state.summary || state.isProcessing || isChatting || !inputMessage.trim()}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 text-white px-4 rounded-xl hover:bg-indigo-700 transition-all shadow-sm disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center min-w-[48px]"
                  >
                    {isChatting ? (
                      <i className="fas fa-spinner fa-spin"></i>
                    ) : (
                      <i className="fas fa-paper-plane"></i>
                    )}
                  </button>
                </form>
                {!state.summary && (
                  <p className="text-center text-[10px] font-medium text-amber-600 mt-2 uppercase tracking-tighter">
                    <i className="fas fa-lock mr-1"></i> Summarize context to unlock chat
                  </p>
                )}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

export interface Message {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  isError?: boolean;
}

export type AppLanguage = 'en' | 'th';

export interface AnalysisState {
  rawContext: string;
  summary: string;
  isProcessing: boolean;
  excludeCode: boolean;
  focusKeywords: string;
  error: string | null;
  language: AppLanguage;
}

export enum TabType {
  SUMMARY = 'summary',
  CHAT = 'chat'
}

import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Message, AppLanguage } from "../types";

const API_KEY = process.env.API_KEY || "";

export class GeminiService {
  private ai: GoogleGenAI;
  private chatInstance: Chat | null = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async summarize(
    context: string, 
    excludeCode: boolean, 
    focusKeywords: string,
    language: AppLanguage
  ): Promise<string> {
    const langNote = language === 'th' ? "Respond in Thai language." : "Respond in English language.";
    const prompt = `
      Please provide a comprehensive summary of the following content.
      ${langNote}

      ${excludeCode ? "IMPORTANT: Exclude all technical code blocks, snippets, or implementation details. Focus only on the conceptual discussion and outcomes." : "Include relevant code concepts if they are central to the discussion."}
      ${focusKeywords ? `ADDITIONAL FOCUS: Prioritize information related to: ${focusKeywords}` : ""}

      CONTENT TO SUMMARIZE:
      ---
      ${context}
      ---
    `;

    try {
      const response: GenerateContentResponse = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          temperature: 0.7,
          topP: 0.95,
        },
      });
      return response.text || (language === 'th' ? "ไม่พบสรุปข้อมูล" : "No summary generated.");
    } catch (error) {
      console.error("Summarization error:", error);
      throw new Error(language === 'th' ? "สรุปข้อมูลล้มเหลว โปรดตรวจสอบการเชื่อมต่อ" : "Failed to summarize the content. Please check your API key and connection.");
    }
  }

  initChat(context: string, excludeCode: boolean, language: AppLanguage) {
    const langNote = language === 'th' ? "Always respond in Thai language." : "Always respond in English language.";
    this.chatInstance = this.ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `
          You are an expert context analyzer. You are helping the user understand a document or chat log they have provided.
          ${langNote}

          CONTEXT PROVIDED BY USER:
          ---
          ${context}
          ---

          RULES:
          1. Answer questions strictly based on the provided context.
          2. ${excludeCode ? "If the user asks for code, explain the logic but do not provide the actual code blocks as per their 'Exclude Code' preference." : "You may provide code snippets if requested and present in the context."}
          3. If the answer is not in the context, state that clearly in the target language (${language}).
          4. Be concise and professional.
        `,
      },
    });
  }

  async sendMessage(message: string): Promise<string> {
    if (!this.chatInstance) {
      throw new Error("Chat not initialized.");
    }

    try {
      const result = await this.chatInstance.sendMessage({ message });
      return result.text || "I'm sorry, I couldn't process that request.";
    } catch (error) {
      console.error("Chat error:", error);
      throw new Error("Failed to send message.");
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AnalysisState, Message, TabType, AppLanguage } from './types';
import { geminiService } from './services/gemini';

